Sure! Below is an example code for a Discord bot using Discord.js v14 that includes a single slash command called `ban`. This command will allow users with the appropriate permissions to ban a member from the server.

First, you'll need to have Node.js and npm installed. Then, you'll need to install the necessary packages:

```bash
npm install discord.js
```

Now, you can create your bot code:

```javascript
const { Client, GatewayIntentBits, REST, Routes, SlashCommandBuilder, PermissionsBitField } = require('discord.js');
require('dotenv').config(); // for environment variables (optional, recommended)

const token = process.env.TOKEN; // replace with your bot token
const clientId = process.env.CLIENT_ID; // replace with your bot client ID
const guildId = process.env.GUILD_ID; // replace with your guild ID

const client = new Client({ intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildBans, GatewayIntentBits.GuildMembers] });

// Register the /ban command
const commands = [
    new SlashCommandBuilder()
       .setName('ban')
       .setDescription('Ban a user from the server.')
       .addUserOption(option =>
            option.setName('target')
               .setDescription('The user to ban')
               .setRequired(true))
       .addStringOption(option =>
            option.setName('reason')
               .setDescription('The reason for the ban')
               .setRequired(false))
].map(command => command.toJSON());

const rest = new REST({ version: '10' }).setToken(token);

(async () => {
    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(
            Routes.applicationGuildCommands(clientId, guildId),
            { body: commands },
        );

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
})();

client.on('ready', () => {
    console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isCommand()) return;

    const { commandName } = interaction;

    if (commandName === 'ban') {
        if (!interaction.member.permissions.has(PermissionsBitField.Flags.BanMembers)) {
            return interaction.reply('You do not have permission to ban members.');
        }

        const user = interaction.options.getUser('target');
        const member = interaction.guild.members.cache.get(user.id);
        const reason = interaction.options.getString('reason') || 'No reason provided';

        if (member) {
            try {
                await member.ban({ reason });
                await interaction.reply(`${user.tag} has been banned for ${reason}`);
            } catch (error) {
                console.error(error);
                await interaction.reply(`There was an error trying to ban ${user.tag}.`);
            }
        } else {
            await interaction.reply(`User ${user.tag} not found.`);
        }
    }
});

client.login(token);
```

### Explanation:
1. **Imports and Constants:**
    - Import necessary modules and set up environment variables for your bot token, client ID, and guild ID.

2. **Command Registration:**
    - Create and register the `/ban` command. The command is defined using the `SlashCommandBuilder` from `discord.js`, specifying that it needs a user to target and can optionally include a reason for the ban.

3. **Client Setup:**
    - Create a new `Client` instance with the necessary intents.
    - When the client is ready, log in with the token.

4. **Interaction Handling:**
    - Listen for interactions, specifically for the `/ban` command.
    - Check if the user executing the command has the appropriate permissions.
    - Attempt to ban the specified user, providing feedback on success or failure.

### Environment Variables:
You might want to store your token and other sensitive information in environment variables for security reasons. You can create a `.env` file in your project directory with the following content:

```env
TOKEN=your-bot-token
CLIENT_ID=your-client-id
GUILD_ID=your-guild-id
```

And use the `dotenv` package to load these variables into your code.

Remember to replace placeholders (`your-bot-token`, `your-client-id`, `your-guild-id`) with your actual bot token, client ID, and guild ID.

### Running the Bot:
To run the bot, simply execute:
```bash
node your-bot-file.js
```

Make sure to replace `your-bot-file.js` with the name of your JavaScript file.

