```cpp
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(std::string &markdown) {
    std::string html;

    // Header
    markdown = std::regex_replace(markdown, std::regex(R"(^# (.+)$)", std::regex::multiline), "<h1>$1</h1>");
    markdown = std::regex_replace(markdown, std::regex(R"(^## (.+)$)", std::regex::multiline), "<h2>$1</h2>");
    markdown = std::regex_replace(markdown, std::regex(R"(^### (.+)$)", std::regex::multiline), "<h3>$1</h3>");

    // Bold and Italics
    markdown = std::regex_replace(markdown, std::regex(R"(\*\*(.+?)\*\*)"), "<strong>$1</strong>");
    markdown = std::regex_replace(markdown, std::regex(R"(\*(.+?)\*)"), "<em>$1</em>");

    // Links
    markdown = std::regex_replace(markdown, std::regex(R"(\[(.+?)\]\((.+?)\))"), "<a href=\"$2\">$1</a>");

    html = markdown;
    return html;
}

int main() {
    std::string markdownText = "# Header 1\n"
                               "## Header 2\n"
                               "### Header 3\n"
                               "This is **bold** and this is *italic*.\n"
                               "[This is a link](https://example.com)";

    std::string htmlText = markdownToHtml(markdownText);
    std::cout << htmlText << std::endl;

    return 0;
}
```

### Explanation:
- **Headers**: The function uses regular expressions to match markdown headers (`#`, `##`, and `###`) and replace them with their HTML counterparts (`<h1>`, `<h2>`, and `<h3>`).
- **Bold and Italics**: Regular expressions are used to replace `**text**` with `<strong>text</strong>` and `*text*` with `<em>text</em>`.
- **Links**: The function replaces `[text](url)` with `<a href="url">text</a>`.

This basic function covers some of the most common markdown elements. For a full-fledged markdown-to-HTML converter, you might want to look into existing libraries such as [cmark](https://github.com/commonmark/cmark), which provides more comprehensive support for markdown syntax.

